function [nmbScnOut,scanOut,scnDir] = fScanDirLstPhosV01(mDir,nmbScn,scan)%% search directory, return number of scan, scan array, scan directory%% [nmbScnOut,scanOut,scnDir] = fScanDirLstPhosV01(nmbScn,scan)%% mDir: mother directory% nmbScn: number of scan to go through% scan: array of scan numbers%% nmbScnOut: number of scan with files% scanOut: array of scan numbers% Written by Kei Nakamura% Created on Wednesday, December 15th 2010.% Modified on%% main bodykk = 0;for jj=1:nmbScn    scanNS = fGet3NmbStringV01(scan(jj));    phsDir = [mDir,'/Scan',scanNS,'/PhosphorScreen'];    bgLst = dir([phsDir,'/Scan',scanNS,'_BG*.png']);    % bg list    imgLst = dir([phsDir,'/Scan',scanNS,'_Phosphor_*.png']);    % image list    datName = [mDir,'/Scan',scanNS,'/ScanDataScan',scanNS,'.txt'];  % data name        bgEx = numel(bgLst)>=1;    imgEx = numel(imgLst)>=1;    datEx = exist(datName, 'file');        if bgEx&&imgEx&&datEx        kk = kk + 1;        scanOut(kk) = scan(jj);        scnDir{kk} = ['Scan',scanNS];    endendnmbScnOut = kk;
